#!/usr/bin/env node
/**
 * Mount integrity check — verify gate for tamper-evidence.
 * Reads src/mount/integrity.json (generated by signer phase),
 * recomputes hashes, and fails on any mismatch.
 *
 * Modes:
 *   --pre-check  Run BEFORE mapper:all to detect unauthorized edits.
 *                Missing integrity.json → skip (first run).
 *                Errors → warn but exit 0 (mapper:all will fix).
 *   (default)    Run AFTER mapper:all. Errors → exit 1.
 *
 * Contract refs:
 *   - guard: mount.integrity.signature-match
 *   - contract:BUILDTIME.app.mapper.phases.signer
 *
 * Recovery: npm run mapper:all
 */

import { readFileSync, readdirSync, existsSync } from 'node:fs';
import { join, relative } from 'node:path';
import { createHash } from 'node:crypto';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const ROOT_DIR = join(__filename, '..', '..', '..');
const MOUNT_DIR = join(ROOT_DIR, 'src', 'mount');
const INTEGRITY_FILE = join(MOUNT_DIR, 'integrity.json');

const EXCLUDED = new Set(['integrity.json', 'AGENTS.md']);

const PRE_CHECK = process.argv.includes('--pre-check');

function collectFiles(dir, base = dir) {
    const results = [];
    if (!existsSync(dir)) return results;

    for (const entry of readdirSync(dir, { withFileTypes: true })) {
        const fullPath = join(dir, entry.name);
        const relPath = relative(base, fullPath).split('\\').join('/');

        if (entry.isDirectory()) {
            results.push(...collectFiles(fullPath, base));
        } else if (entry.isFile() && !EXCLUDED.has(entry.name)) {
            results.push({ relPath, fullPath });
        }
    }
    return results;
}

function hashFile(filePath) {
    const content = readFileSync(filePath);
    return createHash('sha256').update(content).digest('hex');
}

// --- Main ---

if (!existsSync(INTEGRITY_FILE)) {
    if (PRE_CHECK) {
        console.log('⏭️  Pre-check: no integrity.json yet (first run). Skipping.');
        process.exit(0);
    }
    console.error('❌ Mount integrity manifest not found: src/mount/integrity.json');
    console.error('');
    console.error('   This file is generated by the signer phase of mapper:all.');
    console.error('   Recovery: npm run mapper:all');
    process.exit(1);
}

const manifest = JSON.parse(readFileSync(INTEGRITY_FILE, 'utf-8'));
const expectedFiles = manifest.files;

const actualFiles = collectFiles(MOUNT_DIR);
actualFiles.sort((a, b) => a.relPath.localeCompare(b.relPath));

const errors = [];

// Check each expected file
for (const [relPath, expectedHash] of Object.entries(expectedFiles)) {
    const fullPath = join(MOUNT_DIR, relPath);
    if (!existsSync(fullPath)) {
        errors.push({ file: relPath, reason: 'MISSING — file deleted after mapper run' });
        continue;
    }
    const actualHash = hashFile(fullPath);
    if (actualHash !== expectedHash) {
        errors.push({ file: relPath, reason: 'MODIFIED — content changed after mapper run' });
    }
}

// Check for unexpected new files
const expectedSet = new Set(Object.keys(expectedFiles));
for (const { relPath } of actualFiles) {
    if (!expectedSet.has(relPath)) {
        errors.push({ file: relPath, reason: 'ADDED — file not in manifest (created after mapper run)' });
    }
}

if (errors.length > 0) {
    const icon = PRE_CHECK ? '⚠️' : '❌';
    const label = PRE_CHECK
        ? 'TAMPER DETECTED — src/mount/ was edited directly (before mapper regeneration)'
        : 'Mount integrity check FAILED — manual edits detected in src/mount/';
    console.error(`${icon}  ${label}`);
    console.error('');
    for (const { file, reason } of errors) {
        console.error(`   ${file}: ${reason}`);
    }
    console.error('');
    console.error('   Guard: mount.integrity.signature-match');
    if (PRE_CHECK) {
        console.error('   ⚠️  These edits will be OVERWRITTEN by mapper:all.');
        console.error('   If intentional, edit scripts/mapper/surgeon-*.ts instead.');
        // Exit 0 — mapper:all will fix the state, but the warning is logged
        process.exit(0);
    }
    console.error('   Recovery: npm run mapper:all');
    console.error('   Docs: see contract:BUILDTIME.app.mapper.phases.signer');
    process.exit(1);
} else {
    const label = PRE_CHECK ? 'Pre-check' : 'Mount integrity check';
    console.log(`✅ ${label} passed (${Object.keys(expectedFiles).length} files verified)`);
}
